var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"뭐야, 여기가 네 차고라도 되는 줄 알아?","JPN":"何よ？　ここはあなたの車庫なんかじゃないわよ？","ENG":"Huh? You think you own this place?","TWN":"怎麼搞的？你以為這裡是你的車庫嗎？"},"stage":{"bg":"ROOM_04","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"방 좀 빌려줬다고 엉망으로 만들어 놨네.","JPN":"ちょっと部屋を貸してあげたら、めちゃくちゃにしちゃって。","ENG":"I let you stay, and you've made it into this mess.","TWN":"我把房間借給你，結果你把這裡搞得一團糟。"},"stage":{"bg":"ROOM_04","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"WYLER_CHARADE_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"으, 기름 냄새. 샤레이드 최고의 파티 플레이스가 꼴이 이게 뭐람.","JPN":"うう、オイル臭い。シャレード一のパーティープレイスがなんて様なのかしら。","ENG":"Ugh, the smell of grease. You ruined Charade's best party place.","TWN":"唔，好臭的汽油味，怎麼把查雷德最屌的派對地點搞成這樣啦！"},"stage":{"bg":"ROOM_04","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"WYLER_CHARADE_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"WYLER_CHARADE_NPC_NULL","text":{"KOREA":"다음 경기에 내보낼 테니 만전을 기하라고 한 건 당신이었을 텐데.","JPN":"次の試合に出すから、十分に準備しておけと言ったのはお前だったはずだが。","ENG":"You're the one who told me to get ready to be sent out on the next match.","TWN":"你不是說下一場比賽要派我上場，要我做好萬全準備嗎？"},"stage":{"bg":"ROOM_04","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"WYLER_CHARADE_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"만전을 기한다고 준비하는 게 겨우 민수용 아라크네야?","JPN":"十分準備するっていうのが、たかが民需用アラクネなの？","ENG":"And all you've prepared so far is a civilian version of Arachne?","TWN":"你所謂的萬全準備就是民用阿拉克涅？"},"stage":{"bg":"ROOM_04","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WYLER_CHARADE_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"나는 네 총 다루는 솜씨를 높이 사서 불러 온 거야. 그깟 손 재주가 아니라.","JPN":"私は、あなたの銃さばきを高く評価して呼んだのよ。そういう器用さじゃなくてね。","ENG":"I got you out for your gunslinging skills. Not your tinkering skills.","TWN":"我找你來是因為你的槍法過人，不是找你來當黑手的。"},"stage":{"bg":"ROOM_04","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"WYLER_CHARADE_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"WYLER_CHARADE_NPC_NULL","text":{"KOREA":"기계에 대해서는 문외한이로군.","JPN":"機械については素人なんだな。","ENG":"It's obvious that you know nothing about machines.","TWN":"看來在機械方面你是門外漢呢。"},"stage":{"bg":"ROOM_04","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"WYLER_CHARADE_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"WYLER_CHARADE_NPC_NULL","text":{"KOREA":"확실히 이것들은 평범한 민수용 아라크네다. 하지만 이걸 쓴다면…… 이야기가 다르지.","JPN":"確かにこれらは普通の民需用アラクネだ。だが、これを付ければ……話は違う。","ENG":"Yes, these are just ordinary civilian Arachnes. But with this... they become something else.","TWN":"這些確實是普通的民用阿拉克涅，但只要用上這個……就完全是另一個層次。"},"stage":{"bg":"ROOM_04","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"WYLER_CHARADE_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"벌레잖아? 곤충 채집 좋아할 나이란 말은 처음 듣는데?","JPN":"虫？　昆虫採集が好きな歳だったなんて、聞いてないわよ。","ENG":"A bug? I didn't know you were at that age of catching bugs.","TWN":"這不是蟲嗎？原來你還在喜歡抓昆蟲的年紀嗎？"},"stage":{"bg":"ROOM_04","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"WYLER_CHARADE_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"WYLER_CHARADE_NPC_NULL","text":{"KOREA":"너무 비아냥거리진 마, 챔피언.","JPN":"あまり皮肉るな、チャンピオン。","ENG":"Don't be so sarcastic, champion.","TWN":"冠軍，說話不需要那麼酸。"},"stage":{"bg":"ROOM_04","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"WYLER_CHARADE_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"WYLER_CHARADE_NPC_NULL","text":{"KOREA":"이건 예전 동업자에게 받은 기생충이다.","JPN":"これは昔、同業者からもらった寄生虫だ。","ENG":"This is a parasite I got from my former partner.","TWN":"這個寄生蟲是我以前的同事給我的。"},"stage":{"bg":"ROOM_04","slots":{"L":null,"C":{"char_id":"WYLER_CHARADE_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"WYLER_CHARADE_NPC_NULL","text":{"KOREA":"기갑병기의 인공지능을 강제로 오버클럭시켜서 카탈로그보다 몇 배나 뛰어난 성능을 내게 하지.","JPN":"機甲兵器の人工知能を強制オーバークロックさせ、カタログより何倍も優れた性能を発揮させる。","ENG":"It forcefully overclocks the armored unit's AI, causing it to perform several times better than stated in the catalog.","TWN":"牠可以強制使機甲兵器的人工智慧超頻，發揮出比原設定高出好幾倍的性能。"},"stage":{"bg":"ROOM_04","slots":{"L":null,"C":{"char_id":"WYLER_CHARADE_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"WYLER_CHARADE_NPC_NULL","text":{"KOREA":"프레임은 오래 못 버티겠지만, 망가지기 전까진 군용 이상의 위력을 보여줄 거다.","JPN":"フレームは長持ちしないが、壊れるまでは軍用以上の威力を見せてくれるはずだ。","ENG":"Though its frame won't hold for long, it will output more power than its military counterpart until it breaks down.","TWN":"雖然機體本身無法撐太久，但在損壞前會展現出超出軍用以上的威力。"},"stage":{"bg":"ROOM_04","slots":{"L":null,"C":{"char_id":"WYLER_CHARADE_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"그걸, 주최 측을 속이고 값싼 포인트로 쓰겠다는 거구나?","JPN":"それを、主催側を騙して安いポイントで使うってわけね。","ENG":"So you're spending fewer points by deceiving the organizers, eh?","TWN":"原來你是想瞞過主辦方的眼睛，以便宜的點數使用它？"},"stage":{"bg":"ROOM_04","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WYLER_CHARADE_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"WYLER_CHARADE_NPC_NULL","text":{"KOREA":"그뿐만이 아니야. 소프트웨어도 조금 손봤지.","JPN":"それだけじゃない。ソフトウェアにも少し手を加えた。","ENG":"Not just that. I've also configured its software.","TWN":"不只如此，軟體的部分我也有動一點手腳。"},"stage":{"bg":"ROOM_04","slots":{"L":null,"C":{"char_id":"WYLER_CHARADE_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"WYLER_CHARADE_NPC_NULL","text":{"KOREA":"기체가 망가질 때 쯤이면 녀석들에게 달라붙어서…… ","JPN":"機体が壊れる頃には奴らにくっついて…… ","ENG":"When it's about to break down, it will latch itself to the enemy and...","TWN":"等機體快要不行時，就會撲向對方…… "},"stage":{"bg":"ROOM_04","slots":{"L":null,"C":{"char_id":"WYLER_CHARADE_NPC_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};